Parameter Type Description <code>g_renamed_from_member_name</code> VARCHAR2 Original member name before rename <code>g_renamed_from_member_id</code> NUMBER Original member ID <p>Example Usage: </p><pre><code>IF ew_lb_api.g_action_code = 'R' THEN
  log('Renaming member from ' || ew_lb_api.g_renamed_from_member_name || 
      ' to ' || ew_lb_api.g_member_name);
END IF;
</code></pre><p></p>

Parameter Type Description <code>g_moved_from_member_name</code> VARCHAR2 Original parent for move operations <code>g_moved_to_member_name</code> VARCHAR2 Target parent for move operations <p>Example Usage: </p><pre><code>IF ew_lb_api.g_action_code IN ('M', 'ZC', 'ZS') THEN
  log('Moving member from parent ' || ew_lb_api.g_moved_from_member_name || 
      ' to parent ' || ew_lb_api.g_moved_to_member_name);
END IF;
</code></pre><p></p>

Parameter Type Description <code>g_prop_names_tbl</code> ARRAY Property names array <code>g_prop_labels_tbl</code> ARRAY Property labels array <code>g_prop_values_tbl</code> ARRAY Property values array <p>Accessing Property Arrays: </p><pre><code>FOR i IN 1..ew_lb_api.g_prop_names_tbl.COUNT LOOP
  log('Property: ' || ew_lb_api.g_prop_names_tbl(i) || 
      ' = ' || ew_lb_api.g_prop_values_tbl(i));
END LOOP;
</code></pre><p></p>

Parameter Type Description <code>g_out_member_name</code> VARCHAR2 Mapped member name in target <code>g_out_parent_member_name</code> VARCHAR2 Mapped parent name in target <p>Example - Transform Member Names: </p><pre><code>-- Add prefix to member names
ew_lb_api.g_out_member_name := 'BU_' || ew_lb_api.g_member_name;
ew_lb_api.g_out_parent_member_name := 'BU_' || ew_lb_api.g_parent_member_name;
</code></pre><p></p>

Parameter Type Description <code>g_out_new_member_name</code> VARCHAR2 New name for rename operations <code>g_out_old_member_name</code> VARCHAR2 Original name for tracking <p>Example - Handle Renames: </p><pre><code>IF ew_lb_api.g_action_code = 'R' THEN
  ew_lb_api.g_out_old_member_name := ew_lb_api.g_renamed_from_member_name;
  ew_lb_api.g_out_new_member_name := 'NEW_' || ew_lb_api.g_member_name;
END IF;
</code></pre><p></p>

Parameter Type Description <code>g_out_moved_to_member_name</code> VARCHAR2 Target parent for move operations <code>g_out_moved_from_member_name</code> VARCHAR2 Source parent for tracking <p>Example - Redirect Moves: </p><pre><code>IF ew_lb_api.g_action_code IN ('M', 'ZC') THEN
  -- Redirect all moves to a specific parent
  ew_lb_api.g_out_moved_to_member_name := 'UNMAPPED_ENTITIES';
END IF;
</code></pre><p></p>

Parameter Type Description <code>g_out_shared_members_tbl</code> ARRAY Array of shared member locations <code>g_out_shared_parent_tbl</code> ARRAY Parents for shared members <p>Working with Shared Members: </p><pre><code>DECLARE
  l_idx NUMBER := 0;
BEGIN
  -- Add shared member instances
  l_idx := l_idx + 1;
  ew_lb_api.g_out_shared_members_tbl(l_idx) := 'SharedMember1';
  ew_lb_api.g_out_shared_parent_tbl(l_idx) := 'Parent1';

  l_idx := l_idx + 1;
  ew_lb_api.g_out_shared_members_tbl(l_idx) := 'SharedMember1';
  ew_lb_api.g_out_shared_parent_tbl(l_idx) := 'Parent2';
END;
</code></pre><p></p>

Parameter Type Description <code>g_out_prop_names_tbl</code> ARRAY Property names to sync <code>g_out_prop_values_tbl</code> ARRAY Property values to sync <p>Example - Map Properties: </p><pre><code>-- Map specific properties to target
ew_lb_api.g_out_prop_names_tbl(1) := 'ACCOUNT_TYPE';
ew_lb_api.g_out_prop_values_tbl(1) := 'Revenue';

ew_lb_api.g_out_prop_names_tbl(2) := 'CONSOLIDATION';
ew_lb_api.g_out_prop_values_tbl(2) := 'FULL';
</code></pre><p></p>
